/* _breakpoints.scss */
$breakpoints: (
  'sm':  640px,
  'md':  768px,
  'lg': 1024px,
  'xl': 1280px,
);

@mixin respond-to($bp) {
  @media (min-width: map-get($breakpoints, $bp)) {
    @content;
  }
}

/* Usage */
.card {
  padding: 16px;

  @include respond-to('md') {
    padding: 24px;
  }
}

h1 {
  /* 1.5rem on small screens, scales up, caps at 3rem */
  font-size: clamp(1.5rem, 4vw + 0.5rem, 3rem);
}

.section {
  /* 16px on mobile, 64px on desktop — fluid in between */
  padding-block: clamp(1rem, 5vw, 4rem);
}

.container {
  /* Centered column, never touches edges, max 1200px */
  width: min(1200px, 100% - 32px);
  margin-inline: auto;
}

.card-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 24px;
}

/* Result:
  - narrow container: 1 column
  - medium container: 2–3 columns
  - wide container: 4+ columns
  No @media required */

.tag-list {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.tag-list > * {
  flex: 0 0 auto;  /* don't stretch, wrap naturally */
}

.card-wrapper {
  container-type: inline-size;  /* opt in to size queries */
  container-name: card;         /* optional — for nested targeting */
}

/* The card adapts to its container's width */
@container card (min-width: 400px) {
  .card {
    display: grid;
    grid-template-columns: 120px 1fr;
  }

  .card__image {
    aspect-ratio: 1;
  }
}

@container card (min-width: 600px) {
  .card__actions {
    flex-direction: row;
  }
}

.card__title {
  font-size: clamp(1rem, 5cqi, 1.5rem);
  /* cqi = % of container inline size */
}

img {
  max-width: 100%;
  height: auto;   /* maintain aspect ratio */
  display: block;
}

import { BreakpointObserver, Breakpoints } from '@angular/cdk/layout';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class LayoutService {
  private breakpointObserver = inject(BreakpointObserver);

  readonly isMobile = toSignal(
    this.breakpointObserver
      .observe([Breakpoints.Handset])
      .pipe(map(result => result.matches)),
    { initialValue: false }
  );

  readonly isTablet = toSignal(
    this.breakpointObserver
      .observe([Breakpoints.Tablet])
      .pipe(map(result => result.matches)),
    { initialValue: false }
  );
}

@Component({
  template: `
    @if (layout.isMobile()) {
      <app-mobile-nav />
    } @else {
      <app-desktop-nav />
    }
  `
})
export class AppComponent {
  layout = inject(LayoutService);
}

.nav__toggle-input { display: none; }

.nav__links {
  display: none;       /* hidden on mobile */
  flex-direction: column;
  width: 100%;
}

.nav__toggle-input:checked ~ .nav__links {
  display: flex;       /* show when checkbox checked */
}

@media (min-width: 768px) {
  .nav__toggle-btn { display: none; }
  .nav__links {
    display: flex;
    flex-direction: row;
    width: auto;
  }
}

@Component({
  selector: 'app-nav',
  template: `
    <nav class="nav">
      <a routerLink="/">Logo</a>
      <button
        class="nav__toggle"
        [attr.aria-expanded]="menuOpen()"
        (click)="menuOpen.set(!menuOpen())"
        aria-controls="nav-menu"
      >
        <span class="sr-only">{{ menuOpen() ? 'Close' : 'Open' }} menu</span>
        <app-icon [name]="menuOpen() ? 'close' : 'menu'" />
      </button>
      <ul id="nav-menu" [class.is-open]="menuOpen()">
        @for (link of links; track link.path) {
          <li><a [routerLink]="link.path">{{ link.label }}</a></li>
        }
      </ul>
    </nav>
  `
})
export class NavComponent {
  menuOpen = signal(false);
  links = [
    { path: '/about', label: 'About' },
    { path: '/work', label: 'Work' },
    { path: '/contact', label: 'Contact' },
  ];
}

.table-wrapper {
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}

table {
  min-width: 600px;  /* table keeps its structure; wrapper scrolls */
  border-collapse: collapse;
}

/* Each row becomes a card on small screens */
@media (max-width: 599px) {
  table, thead, tbody, tr, th, td {
    display: block;
  }

  thead tr {
    position: absolute;
    top: -9999px;   /* hide header row visually */
    left: -9999px;
  }

  td {
    position: relative;
    padding-left: 50%;
  }

  td::before {
    position: absolute;
    left: 8px;
    width: 45%;
    content: attr(data-label);
    font-weight: 700;
  }
}

:root {
  --safe-top:    env(safe-area-inset-top, 0px);
  --safe-right:  env(safe-area-inset-right, 0px);
  --safe-bottom: env(safe-area-inset-bottom, 0px);
  --safe-left:   env(safe-area-inset-left, 0px);
}

.bottom-nav {
  /* Add home indicator height to bottom padding */
  padding-bottom: calc(16px + env(safe-area-inset-bottom, 0px));
}

.full-screen-modal {
  padding:
    env(safe-area-inset-top, 0px)
    env(safe-area-inset-right, 0px)
    env(safe-area-inset-bottom, 0px)
    env(safe-area-inset-left, 0px);
}

// src/styles/_breakpoints.scss
$bp-sm:  640px;
$bp-md:  768px;
$bp-lg: 1024px;
$bp-xl: 1280px;

@mixin sm  { @media (min-width: $bp-sm)  { @content; } }
@mixin md  { @media (min-width: $bp-md)  { @content; } }
@mixin lg  { @media (min-width: $bp-lg)  { @content; } }
@mixin xl  { @media (min-width: $bp-xl)  { @content; } }

@mixin dark { @media (prefers-color-scheme: dark) { @content; } }
@mixin motion-ok { @media (prefers-reduced-motion: no-preference) { @content; } }

// hero.component.scss
@use '../../../styles/breakpoints' as bp;

:host {
  display: grid;
  padding: 24px 16px;

  @include bp.md {
    padding: 48px 32px;
    grid-template-columns: 1fr 1fr;
  }

  @include bp.lg {
    padding: 80px 64px;
  }
}
